class Solution3 {
public:
    int maxMoves(vector<vector<int>>& grid) {
        unordered_set<int> q;
        for (int r = 0; r < size(grid); ++r) {
            q.emplace(r);
        }
        int c = 0;
        for (; c < size(grid[0]) - 1; ++c) {
            unordered_set<int> new_q;
            for (const auto& r : q) {
                if (grid[r][c] < grid[r][c + 1]) {
                    new_q.emplace(r);
                }
                if (r - 1 >= 0 && grid[r][c] < grid[r - 1][c + 1]) {
                    new_q.emplace(r - 1);
                }
                if (r + 1 < size(grid) && grid[r][c] < grid[r + 1][c + 1]) {
                    new_q.emplace(r + 1);
                }
            }
            q = move(new_q);
            if (empty(q)) {
                break;
            }
        }
        return c;
    }
};

